callGraph.callee:
fetch(url, {
		method: 'POST',
		headers: {
			'Authorization': `Bearer ${matrixAccessToken}`,
			'Content-Type': 'application/json',
			'X-CSRF-TOKEN': csrfToken,
			...(isLocalDevelopment ? { 'X-WHITELIST-HEADER': csrfToken } : {})
		},
		credentials: 'include',
		body: JSON.stringify(messageBody)
	}).then(response => {
		// console.log('📨 MATRIX: File message response status:', response.status);
		if (!response.ok) {
			throw new Error(`Failed to send file message: ${response.status}`);
		}
		return response.json();
	}).then

fetch(url, {
		method: 'POST',
		headers: {
			'Authorization': `Bearer ${matrixAccessToken}`,
			'Content-Type': 'application/json',
			'X-CSRF-TOKEN': csrfToken,
			...(isLocalDevelopment ? { 'X-WHITELIST-HEADER': csrfToken } : {})
		},
		credentials: 'include',
		body: JSON.stringify(messageBody)
	}).then

Promise.all([
		// Skip RocketChat logout due to configuration issues
		// apiRocketchatLogout(),
		apiKeycloakLogout(),
		featureAppointmentsEnabled && calcomLogout(),
		featureToolsEnabled && budibaseLogout()
	]).finally

apiPostError({
						name: error.name,
						message: error.message,
						stack: error.stack,
						level: ERROR_LEVEL_WARN
					}).then

(function waitForLogin(tryCount = 0) {
					const iframe = document.getElementById('authIframe');
					if ((iframe as any)?.contentDocument && tryCount < 3) {
						setTimeout(() => waitForLogin(tryCount + 1), 1000);
						return;
					} else {
						resolve(undefined);
					}
				})

fetch(req)
			.then((response) => {
				if (response.status === 200) {
					const data = response.json();
					resolve(data);
				} else if (response.status === 401) {
					reject(new Error('keycloakLogin'));
				}
			})
			.catch

init(
			{
				...settings.i18n,
				...(tenant?.settings?.activeLanguages && {
					supportedLngs: [
						'de@informal',
						...(tenant?.settings?.activeLanguages || []),
						// If tenant service has 'de' active add default supported languages 'de' and 'de@informal'
						// If 'de' is deactivated 'de@informal' should not be available too
						...(settings.i18n.supportedLngs &&
						(tenant?.settings?.activeLanguages ?? []).includes('de')
							? settings.i18n.supportedLngs
							: [])
					]
				})
			},
			settings.translation
		).then

apiPostError({
			name: e.name,
			message: e.message,
			stack: e.stack,
			level: ERROR_LEVEL_WARN
		}).then
